//SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

import {INameWrapper, PARENT_CANNOT_CONTROL, CAN_EXTEND_EXPIRY, IS_DOT_ETH} from "./wrapper/INameWrapper.sol";

/// @notice Simple forever subname registrar for wrapped ENS names
contract ForeverSubnameRegistrar {
    INameWrapper public immutable nameWrapper;
    bytes32 public immutable parentNode;
    address public immutable resolver;

    uint64 private constant GRACE_PERIOD = 90 days;

    event NameRegistered(string label, address owner, bytes32 node);

    constructor(address _nameWrapper, bytes32 _parentNode, address _resolver) {
        nameWrapper = INameWrapper(_nameWrapper);
        parentNode = _parentNode;
        resolver = _resolver;
    }

    /// @notice Register a subname under the parent node
    /// @param label The label for the subname (e.g., "one" for one.support.eth)
    /// @param owner The address that will own the subname
    function register(string calldata label, address owner) external {
        (, uint32 parentFuses, uint64 parentExpiry) = nameWrapper.getData(
            uint256(parentNode)
        );

        // Calculate expiry based on parent
        uint64 expiry = parentExpiry;
        if (parentFuses & IS_DOT_ETH == IS_DOT_ETH) {
            expiry = parentExpiry - GRACE_PERIOD;
        }

        // Register the subname with fuses that make it "forever" (until parent expires)
        nameWrapper.setSubnodeRecord(
            parentNode,
            label,
            owner,
            resolver,
            0, // ttl
            PARENT_CANNOT_CONTROL | CAN_EXTEND_EXPIRY,
            expiry
        );

        bytes32 node = keccak256(
            abi.encodePacked(parentNode, keccak256(bytes(label)))
        );
        emit NameRegistered(label, owner, node);
    }

    /// @notice Check if a subname is available
    /// @param label The label to check
    function available(string calldata label) external view returns (bool) {
        bytes32 node = keccak256(
            abi.encodePacked(parentNode, keccak256(bytes(label)))
        );
        try nameWrapper.getData(uint256(node)) returns (
            address,
            uint32,
            uint64 expiry
        ) {
            return expiry < block.timestamp;
        } catch {
            return true;
        }
    }
}

